277	// Mount attaches another http.Handler or chi Router as a subrouter along a routing
278	// path. It's very useful to split up a large API as many independent routers and
279	// compose them as a single service using Mount. See _examples/.
280	//
281	// Note that Mount() simply sets a wildcard along the `pattern` that will continue
282	// routing at the `handler`, which in most cases is another chi.Router. As a result,
283	// if you define two Mount() routes on the exact same pattern the mount will panic.
284	func (mx *Mux) Mount(pattern string, handler http.Handler) {
285		if handler == nil {
286			panic(fmt.Sprintf("chi: attempting to Mount() a nil handler on '%s'", pattern))
287		}
288	
289		// Provide runtime safety for ensuring a pattern isn't mounted on an existing
290		// routing pattern.
291		if mx.tree.findPattern(pattern+"*") || mx.tree.findPattern(pattern+"/*") {
292			panic(fmt.Sprintf("chi: attempting to Mount() a handler on an existing path, '%s'", pattern))
293		}
