package chi

import (
	"net/http"
	"strconv"
	"strings"
)

// CORSOptions describes the configuration for chi's built-in Cross-Origin
// Resource Sharing (CORS) support.
type CORSOptions struct {
	// AllowOrigin sets the Access-Control-Allow-Origin header value.
	AllowOrigin string

	// AllowMethods sets the Access-Control-Allow-Methods header value used
	// for preflight requests whenever the methods available on the matched
	// route cannot be detected.
	AllowMethods []string

	// AllowHeaders sets the Access-Control-Allow-Headers header value.
	AllowHeaders []string

	// ExposeHeaders sets the Access-Control-Expose-Headers header value.
	ExposeHeaders []string

	// MaxAge sets the Access-Control-Max-Age header value, in seconds.
	MaxAge int

	// AllowCredentials sets the Access-Control-Allow-Credentials header value.
	AllowCredentials bool
}

// DefaultCORSOptions returns a CORSOptions with sensible defaults: a
// wildcard origin, a common set of allowed headers/methods, and a 1 hour
// (3600 second) max age for preflight caching.
func DefaultCORSOptions() CORSOptions {
	return CORSOptions{
		AllowOrigin: "*",
		AllowMethods: []string{
			http.MethodGet,
			http.MethodHead,
			http.MethodPost,
			http.MethodPut,
			http.MethodPatch,
			http.MethodDelete,
			http.MethodOptions,
		},
		AllowHeaders: []string{
			"Accept",
			"Authorization",
			"Content-Type",
			"X-CSRF-Token",
		},
		ExposeHeaders:    []string{},
		MaxAge:           3600,
		AllowCredentials: false,
	}
}

// CORS returns a middleware that applies Cross-Origin Resource Sharing
// response headers to every request, based on options.
//
// CORS only sets the "always on" response headers (Access-Control-Allow-Origin,
// Access-Control-Allow-Credentials and Access-Control-Expose-Headers). Preflight
// OPTIONS requests and the Access-Control-Allow-Methods/-Allow-Headers/-Max-Age
// headers they require are handled by the router's MethodNotAllowed handler,
// see Mux.EnableCORS and Mux.EnableCORSWithOptions which wire this up
// automatically.
func CORS(options CORSOptions) func(http.Handler) http.Handler {
	exposeHeaders := strings.Join(options.ExposeHeaders, ", ")

	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			header := w.Header()

			header.Set("Access-Control-Allow-Origin", options.AllowOrigin)
			if exposeHeaders != "" {
