// corsPreflightHandler builds the handler chi's router calls whenever a
// request's method didn't match a registered route (see Mux.MethodNotAllowed).
// It answers preflight OPTIONS requests with a 204 and the CORS headers
// browsers require, detecting Access-Control-Allow-Methods from the matched
// route when possible, and otherwise responds with a plain 405 plus an Allow
// header, as chi does by default.
func corsPreflightHandler(options CORSOptions) http.HandlerFunc {
	allowHeaders := strings.Join(options.AllowHeaders, ", ")
	maxAge := strconv.Itoa(options.MaxAge)
	defaultAllowMethods := strings.Join(options.AllowMethods, ", ")

	return func(w http.ResponseWriter, r *http.Request) {
		allowMethods := defaultAllowMethods
		if rctx := RouteContext(r.Context()); rctx != nil {
			if methods := rctx.AllowedMethods(); len(methods) > 0 {
				allowMethods = strings.Join(methods, ", ")
			}
		}

		if r.Method == http.MethodOptions {
			header := w.Header()
			header.Set("Access-Control-Allow-Methods", allowMethods)
			header.Set("Access-Control-Allow-Headers", allowHeaders)
			header.Set("Access-Control-Max-Age", maxAge)
			w.WriteHeader(http.StatusNoContent)
			return
		}

		w.Header().Set("Allow", allowMethods)
		w.WriteHeader(http.StatusMethodNotAllowed)
	}
}

